const EVENT_KEY = 'fundflow_tracking_update';

const DEFAULT_ITEMS: TrackedItem[] = [
  { id: 'RELIANCE', name: 'Reliance Industries Ltd', symbol: 'RELIANCE', type: 'STOCK' },
  { id: 'HDFCBANK', name: 'HDFC Bank Ltd', symbol: 'HDFCBANK', type: 'STOCK' },
