import { useState, useRef, useEffect, useCallback } from 'react';
import { initiateBulkInsightExtraction, pollBulkInsightStatus } from '../services/dataService';
import { processRawInsightData } from '../services/geminiService';
import { getTopElementInnerHTML } from '../services/helper';
import { InsightResultItem, PollStatusResponse } from '../types/trackingTypes';

export const useInsightExtraction = () => {
  const [results, setResults] = useState<Record<string, InsightResultItem[]>>({});
  const [status, setStatus] = useState<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>('idle');

  // Aggregate progress across all batches
  const [progress, setProgress] = useState({ completed: 0, total: 0 });

  // Track multiple active batches (Request IDs)
  const [activeRequestIds, setActiveRequestIds] = useState<Set<string>>(new Set());

  // Track progress of each individual batch to compute total
  const [batchProgress, setBatchProgress] = useState<Record<string, { completed: number; total: number }>>({});

  // Track ongoing Gemini processing to prevent duplicate calls
  const processingRef = useRef<Set<string>>(new Set());

  const startExtraction = useCallback(async (symbols: string[], batchSize = 10) => {
    if (symbols.length === 0) return;

    // Reset State
    setResults({});
    setBatchProgress({});
    setActiveRequestIds(new Set());
    processingRef.current.clear();
    setStatus('initializing');
    setProgress({ completed: 0, total: symbols.length });

    // Create Batches
    const batches: string[][] = [];
    for (let i = 0; i < symbols.length; i += batchSize) {
      batches.push(symbols.slice(i, i + batchSize));
    }

    console.log(`[useInsightExtraction] Starting ${batches.length} batches of size ${batchSize}`);

    // Process Batches in Parallel
    // We launch them all, and the hook state manages the polling for each
    let initiatedBatches = 0;

    batches.forEach(async (batch, index) => {
      try {
        const response = await initiateBulkInsightExtraction(batch);

        if (response && response.requestId) {
          const rId = response.requestId;

          // Register the new batch
          setActiveRequestIds(prev => new Set(prev).add(rId));
          setBatchProgress(prev => ({
            ...prev,
            [rId]: { completed: 0, total: response.totalStocks }
          }));

          // If we have at least one active, we are polling
          setStatus('polling');
        } else {
            console.error(`Batch ${index + 1} failed to initiate`);
        }
      } catch (e) {
        console.error(`Error initiating batch ${index + 1}`, e);
      } finally {
        initiatedBatches++;
        // If all tried and none succeeded (status still initializing), mark error
        if (initiatedBatches === batches.length) {
             setActiveRequestIds(current => {
                 if (current.size === 0) setStatus('error');
                 return current;
             });
        }
      }
    });
  }, []);

  // --- Polling Logic for Multiple Batches ---
  useEffect(() => {
    // If no active requests, we might be done or idle
    if (activeRequestIds.size === 0) {
      if (status === 'polling') {
          setStatus('completed');
      }
      return;
    }

    const pollAll = async () => {
      const ids = Array.from(activeRequestIds);

      await Promise.all(ids.map(async (id) => {
        const data = await pollBulkInsightStatus(id);

        if (data) {
          // 1. Update Results (Merge)
          setResults(prev => {
            const next = { ...prev };
            for (const [symbol, newItems] of Object.entries(data.results)) {
              const existingItems = next[symbol] || [];
              const mergedItems = [...existingItems];

              newItems.forEach(newItem => {
                const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
                if (index > -1) {
                  const existing = mergedItems[index];
                  // Preserve parsed JSON if new data is raw string (polling often returns same raw data)
                  if (existing.type === 'json' && typeof newItem.data === 'string') {
                    // Do nothing, keep existing parsed data
                  } else {
                    mergedItems[index] = newItem;
                  }
                } else {
                  mergedItems.push(newItem);
                }
              });
              next[symbol] = mergedItems;
            }
            return next;
          });

          // 2. Update Batch Progress
          setBatchProgress(prev => ({
            ...prev,
            [id]: { completed: data.completedStocks, total: data.totalStocks }
          }));

          // 3. Check for Completion
          if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks >= data.totalStocks)) {
            setActiveRequestIds(prev => {
              const next = new Set(prev);
              next.delete(id);
              return next;
            });
          }
        }
      }));
    };

    const intervalId = setInterval(pollAll, 5000);
    return () => clearInterval(intervalId);
  }, [activeRequestIds, status]);

  // --- Aggregate Progress ---
  useEffect(() => {
      if (Object.keys(batchProgress).length === 0) return;

      const totals = Object.values(batchProgress).reduce((acc, curr) => ({
          completed: acc.completed + curr.completed,
          total: acc.total + curr.total
      }), { completed: 0, total: 0 });

      // Only update if total > 0 to avoid flickers
      if (totals.total > 0) {
          setProgress(totals);
      }
  }, [batchProgress]);

  // --- Gemini Processing Logic (Same as before) ---
  useEffect(() => {
    Object.entries(results).forEach(([symbol, items]) => {
      items.forEach(async (item) => {
        // Use a composite key including data length/hash if possible, 
        // effectively we assume if data changes, we might want to re-parse, 
        // but here we just check if it's raw HTML and not processed.
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        if (item.geminiParsingReq && 
            item.success && 
            typeof item.data === 'string' && 
            item.data.trim().startsWith('<') &&
            !processingRef.current.has(uniqueKey)
        ) {
            processingRef.current.add(uniqueKey);

            try {
                let dataToParse = item.data;
                if(item.indicatorName === "Insider/SAST Deals") {
                  dataToParse = getTopElementInnerHTML(item.data);
                }

                const jsonStr = await processRawInsightData(dataToParse, item.geminiPrompt, item.indicatorName);

                let jsonObj;
                try {
                    jsonObj = JSON.parse(jsonStr);
                } catch(e) {
                    jsonObj = { error: "Failed to parse data output", raw: jsonStr };
                }

                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: jsonObj,
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            } catch (err) {
                console.error("Processing failed for", uniqueKey);
                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: { error: "Processing failed" },
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            }
        }
      });
    });
  }, [results]);

  return {
    results,
    setResults,
    status,
    setStatus,
    progress,
    setProgress,
    activeRequestIds, // Exposed for debug if needed
    startExtraction
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { Loader2, RefreshCw, Filter, BrainCircuit, ChevronDown, Settings } from 'lucide-react';
import { fetchIndexConstituents } from '../../services/dataService';
import { useInsightExtraction } from '../../hooks/useInsightExtraction';
import { processIndicatorData, ProcessedInsight } from '../../services/indicatorProcessor';
import IntelligentStockCard from './cards/IntelligentStockCard';

interface IntelligentTrackingManagerProps {
  onOpenChat: (context: any[]) => void;
  onSelectStock: (symbol: string, name: string) => void;
}

const INDICES = ["NIFTY 50", "NIFTY BANK", "NIFTY IT", "NIFTY AUTO", "NIFTY PHARMA"];
const FILTER_TYPES = ["All", "Valuation", "Holdings", "Performance", "Deals"];

const IntelligentTrackingManager: React.FC<IntelligentTrackingManagerProps> = ({ 
  onOpenChat, 
  onSelectStock 
}) => {
  const [selectedIndex, setSelectedIndex] = useState("NIFTY 50");
  const [symbols, setSymbols] = useState<string[]>([]);
  const [loadingSymbols, setLoadingSymbols] = useState(false);
  const [selectedFilter, setSelectedFilter] = useState("All");

  // Batch Configuration
  const [batchSize, setBatchSize] = useState(10);
  const [showConfig, setShowConfig] = useState(false);

  // Use existing extraction hook
  const { results, status, startExtraction, progress } = useInsightExtraction();

  // Local state for processed trigger data
  const [processedStocks, setProcessedStocks] = useState<Record<string, ProcessedInsight[]>>({});
  const [processingData, setProcessingData] = useState(false);

  // 1. Fetch Index Symbols on Change
  useEffect(() => {
     const loadSymbols = async () => {
         setLoadingSymbols(true);
         setProcessedStocks({}); // Clear old processed data
         setSymbols([]); // Reset symbols
         try {
             const data = await fetchIndexConstituents(selectedIndex);
             setSymbols(data);
         } catch (e) {
             console.error("Failed to fetch index symbols", e);
             setSymbols([]);
         } finally {
             setLoadingSymbols(false);
         }
     };
     loadSymbols();
  }, [selectedIndex]);

  // 2. Start Extraction when Symbols Loaded
  useEffect(() => {
      if (symbols.length > 0) {
          startExtraction(symbols, batchSize);
      }
  }, [symbols, startExtraction, batchSize]);

  // 3. Process Raw Results into Intelligent Insights
  useEffect(() => {
      const processResults = async () => {
          setProcessingData(true);
          const newProcessed: Record<string, ProcessedInsight[]> = {};

          // Iterate over all results from the hook
          for (const [symbol, items] of Object.entries(results)) {
              const stockInsights: ProcessedInsight[] = [];

              // Only process items that are successful JSON/Data
              for (const item of items) {
                  if (item.success && (item.type === 'json' || item.data)) {
                       const insight = await processIndicatorData(symbol, item.indicatorName, item.data);
                       if (insight.status === 'triggered') {
                           stockInsights.push(insight);
                       }
                  }
              }

              if (stockInsights.length > 0) {
                  newProcessed[symbol] = stockInsights;
              }
          }
          setProcessedStocks(newProcessed);
          setProcessingData(false);
      };

      // Debounce slightly to avoid thrashing during polling
      const timer = setTimeout(processResults, 1000);
      return () => clearTimeout(timer);

  }, [results]);

  // 4. Filter Logic
  const filteredStocks = useMemo(() => {
      return Object.entries(processedStocks).filter(([_, insights]) => {
          if (selectedFilter === "All") return true;
          return insights.some(i => i.type === selectedFilter);
      }).sort((a, b) => b[1].length - a[1].length); // Sort by number of insights desc
  }, [processedStocks, selectedFilter]);


  return (
    <div className="space-y-6">
       {/* Controls Bar */}
       <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">

           <div className="flex items-center gap-4 w-full md:w-auto">
               {/* Index Selector */}
               <div className="relative">
                   <select 
                       value={selectedIndex}
                       onChange={(e) => setSelectedIndex(e.target.value)}
                       className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-4 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                       disabled={loadingSymbols || status === 'initializing'}
                   >
                       {INDICES.map(idx => <option key={idx} value={idx}>{idx}</option>)}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

               {/* Filter Pills */}
               <div className="flex items-center gap-2 overflow-x-auto pb-1 md:pb-0">
                   <Filter size={16} className="text-gray-400 mr-1" />
                   {FILTER_TYPES.map(type => (
                       <button
                           key={type}
                           onClick={() => setSelectedFilter(type)}
                           className={`px-3 py-1.5 rounded-full text-xs font-medium transition-colors whitespace-nowrap ${
                               selectedFilter === type 
                               ? 'bg-indigo-100 text-indigo-700 border border-indigo-200' 
                               : 'bg-white border border-gray-200 text-gray-600 hover:bg-gray-50'
                           }`}
                       >
                           {type}
                       </button>
                   ))}
               </div>
           </div>

           {/* Status Indicator & Settings */}
           <div className="flex items-center gap-3 w-full md:w-auto justify-end relative">

               {/* Batch Config */}
               <div className="relative">
                   <button 
                       onClick={() => setShowConfig(!showConfig)}
                       className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-colors"
                       title="Configuration"
                   >
                       <Settings size={18} />
                   </button>
                   {showConfig && (
                       <div className="absolute top-full right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-100 p-3 z-50">
                           <label className="text-xs font-semibold text-gray-600 mb-1 block">Batch Size</label>
                           <input 
                               type="number" 
                               min="1" 
                               max="50" 
                               value={batchSize}
                               onChange={(e) => setBatchSize(Number(e.target.value))}
                               className="w-full text-sm border border-gray-200 rounded px-2 py-1"
                           />
                           <p className="text-[10px] text-gray-400 mt-1">Number of stocks to process concurrently.</p>
                       </div>
                   )}
               </div>

               {loadingSymbols ? (
                   <span className="text-xs text-gray-500 flex items-center gap-2">
                       <Loader2 size={14} className="animate-spin" /> Fetching Symbols...
                   </span>
               ) : status === 'initializing' || status === 'polling' ? (
                   <div className="flex items-center gap-3">
                       <span className="text-xs text-gray-500 flex items-center gap-2">
                           <Loader2 size={14} className="animate-spin text-indigo-600" /> 
                           Analyzing {progress.completed}/{progress.total}
                       </span>
                   </div>
               ) : (
                   <button 
                       onClick={() => startExtraction(symbols, batchSize)}
                       className="flex items-center gap-2 px-3 py-2 text-gray-600 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-colors text-sm font-medium"
                   >
                       <RefreshCw size={16} /> Refresh
                   </button>
               )}
           </div>
       </div>

       {/* Content Grid */}
       {loadingSymbols ? (
           <div className="flex flex-col items-center justify-center py-20 text-gray-400">
               <Loader2 size={32} className="animate-spin text-indigo-500 mb-2" />
               <p className="text-sm">Loading Index Constituents...</p>
           </div>
       ) : filteredStocks.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
               {filteredStocks.map(([symbol, insights]) => (
                   <IntelligentStockCard 
                       key={symbol}
                       symbol={symbol}
                       insights={insights}
                       onOpenDeepDive={() => onSelectStock(symbol, symbol)}
                       onAskAI={() => onOpenChat(insights.map(i => ({ symbol, type: i.type, insight: i.text, rawData: i.data })))}
                   />
               ))}
           </div>
       ) : (
           <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
               {status === 'initializing' || status === 'polling' || processingData ? (
                   <>
                      <BrainCircuit size={48} className="text-indigo-200 mb-4 animate-pulse" />
                      <h3 className="text-lg font-medium text-gray-900">AI Analysis in Progress</h3>
                      <p className="text-gray-500 mt-1">Processing data in batches of {batchSize}...</p>
                   </>
               ) : (
                   <>
                      <p className="text-gray-500">No stocks found matching your criteria.</p>
                      <p className="text-xs text-gray-400 mt-1">Try changing the filter or refreshing analysis.</p>
                   </>
               )}
           </div>
       )}
    </div>
  );
};

export default IntelligentTrackingManager;

import React from 'react';
import { TrendingUp, Briefcase, Activity, Layers, Plus, Check, ExternalLink } from 'lucide-react';
import { ProcessedInsight } from '../../../services/indicatorProcessor';

interface IntelligentStockCardProps {
  symbol: string;
  insights: ProcessedInsight[];
  isTracked: boolean;
  onToggleTrack: () => void;
  onOpenDeepDive: () => void;
  onAskAI: () => void;
}

const IntelligentStockCard: React.FC<IntelligentStockCardProps> = ({ 
  symbol, 
  insights,
  isTracked,
  onToggleTrack, 
  onOpenDeepDive,
  onAskAI 
}) => {

  const groupInsights = () => {
      const groups = {
          Valuation: [] as ProcessedInsight[],
          Holdings: [] as ProcessedInsight[],
          Performance: [] as ProcessedInsight[],
          Deals: [] as ProcessedInsight[]
      };

      insights.forEach(i => {
          if (i.type && groups[i.type]) {
              groups[i.type].push(i);
          }
      });
      return groups;
  };

  const grouped = groupInsights();
  const hasData = insights.length > 0;

  const renderSection = (title: string, items: ProcessedInsight[], icon: React.ReactNode, bgClass: string, textClass: string) => {
      if (items.length === 0) return null;

      return (
          <div className="mb-3 last:mb-0">
             <div className="flex items-center gap-1.5 mb-1.5">
                <div className={`p-1 rounded ${bgClass} ${textClass}`}>
                    {icon}
                </div>
                <span className={`text-[10px] font-bold uppercase tracking-wider ${textClass}`}>{title}</span>
             </div>
             <div className="space-y-1.5">
                 {items.map((item, idx) => (
                     <div key={idx} className="text-xs text-gray-700 bg-gray-50 p-2 rounded border border-gray-100 leading-snug">
                         {item.text}
                     </div>
                 ))}
             </div>
          </div>
      );
  };

  return (
    <div className="bg-white rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-shadow flex flex-col h-full group">
        {/* Header */}
        <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50/50 rounded-t-xl">
             {/* Clickable Header for Deep Dive */}
             <button 
                onClick={onOpenDeepDive}
                className="flex items-center gap-2 text-left hover:bg-gray-100 p-1 -ml-1 rounded-lg transition-colors flex-1"
                title="Click for Deep Dive Analysis"
             >
                 <div className="w-8 h-8 rounded-lg bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold text-xs shrink-0">
                    {symbol[0]}
                 </div>
                 <div className="min-w-0">
                    <h3 className="font-bold text-gray-900 text-sm leading-tight flex items-center gap-1 truncate">
                        {symbol}
                        <ExternalLink size={10} className="text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </h3>
                    <div className="text-[10px] text-gray-500 font-medium flex items-center gap-1 truncate">
                        {insights.length} Insight{insights.length !== 1 ? 's' : ''} Found
                    </div>
                 </div>
             </button>

             {/* Track Toggle Button */}
             <button 
                onClick={(e) => { e.stopPropagation(); onToggleTrack(); }}
                className={`w-8 h-8 flex items-center justify-center rounded-lg border transition-all ${
                    isTracked 
                    ? 'bg-green-50 border-green-200 text-green-600' 
                    : 'bg-white border-gray-200 text-gray-400 hover:text-indigo-600 hover:border-indigo-200'
                }`}
                title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
             >
                {isTracked ? <Check size={14} /> : <Plus size={14} />}
             </button>
        </div>

        {/* Body */}
        <div className="p-3 flex-1 overflow-y-auto max-h-[300px] custom-scrollbar">
            {hasData ? (
                <>
                   {renderSection("Valuation & Technicals", grouped.Valuation, <Activity size={12}/>, "bg-blue-50", "text-blue-700")}
                   {renderSection("Institutional Holdings", grouped.Holdings, <Briefcase size={12}/>, "bg-purple-50", "text-purple-700")}
                   {renderSection("Performance Trend", grouped.Performance, <TrendingUp size={12}/>, "bg-green-50", "text-green-700")}
                   {renderSection("Deals & Insider", grouped.Deals, <Layers size={12}/>, "bg-orange-50", "text-orange-700")}
                </>
            ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-xs italic">
                    No significant triggers found.
                </div>
            )}
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-gray-100 mt-auto flex gap-2">
             <button 
                onClick={onAskAI}
                className="flex-1 py-1.5 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 rounded text-xs font-medium transition-colors flex items-center justify-center gap-1.5"
             >
                <Briefcase size={12} /> Ask AI
             </button>
        </div>
    </div>
  );
};

