                                key={idx}
                                onClick={(e) => handleToggleIndex(e, idx)}
                                className={`px-4 py-2 text-sm cursor-pointer flex items-center justify-between hover:bg-gray-50 ${isAdded ? 'bg-indigo-50 text-indigo-700' : 'text-gray-700'}`}
                              >
