import { useState, useRef, useEffect, useCallback } from 'react';
import { initiateBulkInsightExtraction, pollBulkInsightStatus, fetchStockSecInfo } from '../services/dataService';
import { processRawInsightData } from '../services/geminiService';
import { getTopElementInnerHTML } from '../services/helper';
import { InsightResultItem, PollStatusResponse } from '../types/trackingTypes';

export const useInsightExtraction = () => {
  const [results, setResults] = useState<Record<string, InsightResultItem[]>>({});
  const [status, setStatus] = useState<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>('idle');

  // Aggregate progress across all batches
  const [progress, setProgress] = useState({ completed: 0, total: 0 });

  // Queue Management State
  const [extractionQueue, setExtractionQueue] = useState<string[]>([]);
  const [activeRequestIds, setActiveRequestIds] = useState<Set<string>>(new Set());
  const [batchProgress, setBatchProgress] = useState<Record<string, { completed: number; total: number }>>({});

  // Refs for logic control
  const isProcessingSuperBatch = useRef(false);
  const configRef = useRef({ batchSize: 10, invalidateCache: false });
  const processingRef = useRef<Set<string>>(new Set());

  const startExtraction = useCallback(async (symbols: string[], batchSize = 10, invalidateCache = false) => {
    if (symbols.length === 0) return;

    // Reset operational state
    setBatchProgress({});
    setActiveRequestIds(new Set());
    processingRef.current.clear();

    // Store config for subsequent batches
    configRef.current = { batchSize, invalidateCache };

    setStatus('initializing');
    setProgress({ completed: 0, total: symbols.length });

    // Load the Queue
    setExtractionQueue(symbols);
  }, []);

  // --- Queue Processing Logic ---
  // This effect acts as the "Manager". It watches the queue and active requests.
  // If no requests are active and queue has items, it fires the next Super Batch.
  useEffect(() => {
    const processQueue = async () => {
        // If everything is done
        if (extractionQueue.length === 0 && activeRequestIds.size === 0 && (status === 'polling' || status === 'initializing')) {
            setStatus('completed');
            return;
        }

        // Conditions to pause:
        // 1. Queue is empty (nothing to do)
        // 2. Requests are active (wait for current super-batch of 50 to finish)
        // 3. Already setting up a batch (prevent race conditions)
        if (extractionQueue.length === 0) return;
        if (activeRequestIds.size > 0) return;
        if (isProcessingSuperBatch.current) return;

        // Start Processing Next Super Batch
        isProcessingSuperBatch.current = true;
        if (status !== 'polling') setStatus('polling');

        try {
            // 1. Slice the Super Batch (Max 50 stocks)
            const SUPER_BATCH_LIMIT = 50;
            const currentBatchSymbols = extractionQueue.slice(0, SUPER_BATCH_LIMIT);
            const remainingSymbols = extractionQueue.slice(SUPER_BATCH_LIMIT);

            // 2. Update Queue immediately
            setExtractionQueue(remainingSymbols);

            console.log(`[Queue Manager] Starting Super Batch of ${currentBatchSymbols.length} stocks. Remaining: ${remainingSymbols.length}`);

            // 3. Split Super Batch into Server-Friendly API Batches (Max 10 per request)
            const { batchSize, invalidateCache } = configRef.current;
            const apiPromises = [];

            for (let i = 0; i < currentBatchSymbols.length; i += batchSize) {
                const chunk = currentBatchSymbols.slice(i, i + batchSize);
                apiPromises.push(initiateBulkInsightExtraction(chunk, invalidateCache));
            }

            // 4. Fire API requests in parallel (Max 5 requests for 50 stocks)
            const responses = await Promise.all(apiPromises);

            // 5. Track the new Request IDs
            const newIds = new Set<string>();
            const newProgressEntry: Record<string, any> = {};

            responses.forEach(res => {
                if (res && res.requestId) {
                    newIds.add(res.requestId);
                    newProgressEntry[res.requestId] = { completed: 0, total: res.totalStocks };
                }
            });

            if (newIds.size > 0) {
                setActiveRequestIds(prev => {
                    const next = new Set(prev);
                    newIds.forEach(id => next.add(id));
                    return next;
                });
                setBatchProgress(prev => ({ ...prev, ...newProgressEntry }));
            } else {
                console.error("All batches in current super-batch failed to initiate.");
                // If we have no active IDs but queue had items, we risk stalling. 
                // However, since we sliced the queue, the effect will run again.
                // If queue is now empty and no IDs, it completes. If queue has items, it tries next batch.
            }

        } catch (e) {
            console.error("Error processing super batch", e);
            setStatus('error');
        } finally {
            isProcessingSuperBatch.current = false;
        }
    };

    processQueue();
  }, [extractionQueue, activeRequestIds, status]);


  // --- Polling Logic ---
  useEffect(() => {
    // Only poll if we have active requests
    if (activeRequestIds.size === 0) return;

    const pollAll = async () => {
      const ids = Array.from(activeRequestIds);

      await Promise.all(ids.map(async (id) => {
        const data = await pollBulkInsightStatus(id);

        if (data) {
          // 1. Update Results (Merge)
          setResults(prev => {
            const next = { ...prev };
            for (const [symbol, newItems] of Object.entries(data.results)) {
              const existingItems = next[symbol] || [];
              const mergedItems = [...existingItems];

              newItems.forEach(newItem => {
                const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
                if (index > -1) {
                  const existing = mergedItems[index];
                  // Preserve parsed JSON if new data is raw string (polling often returns same raw data)
                  if (existing.type === 'json' && typeof newItem.data === 'string') {
                    // Do nothing, keep existing parsed data
                  } else {
                    mergedItems[index] = newItem;
                  }
                } else {
                  mergedItems.push(newItem);
                }
              });
              next[symbol] = mergedItems;
            }
            return next;
          });

          // 2. Update Batch Progress
          setBatchProgress(prev => ({
            ...prev,
            [id]: { completed: data.completedStocks, total: data.totalStocks }
          }));

          // 3. Check for Completion of specific batch
          if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks >= data.totalStocks)) {
            setActiveRequestIds(prev => {
              const next = new Set(prev);
              next.delete(id);
              return next;
            });
          }
        }
      }));
    };

    const intervalId = setInterval(pollAll, 5000);
    return () => clearInterval(intervalId);
  }, [activeRequestIds]);

  // --- Aggregate Progress Calculation ---
  useEffect(() => {
      // Calculate total work: (Stocks already done in previous batches) + (Current batch totals) + (Remaining in queue)
      // This is hard to track perfectly dynamically. 
      // Simplified approach: completed = sum(batchProgress.completed), total = initial total.
      // But we passed total in startExtraction. Let's use the local batch accumulation for 'completed'

      const batchTotals = Object.values(batchProgress).reduce((acc, curr) => ({
          completed: acc.completed + curr.completed,
          total: acc.total + curr.total // This is only total of *active/finished* batches
      }), { completed: 0, total: 0 });

      // We maintain the global 'total' from startExtraction in the 'progress' state 
      // but update 'completed' by adding up what we know.
      // Actually, since we clear batchProgress on start, we need to accumulate completed tasks carefully.
      // Ideally, we can just display the active progress relative to the whole or just show "Processing X of Y"

      // Let's rely on the state set in startExtraction for 'total', and sum up completed from batchProgress + offset?
      // For simplicity in this multi-stage setup:
      // We can just update 'completed' based on batchProgress relative to current active work, 
      // OR better: we can't easily track global completion percent without a persistent counter.
      // Let's update 'completed' = (Total - Queue - Remaining in Active).

      // Better strategy for UI:
      // Completed = Total Requested - Queue Length - (Sum of (BatchTotal - BatchCompleted))

      if (progress.total > 0) {
          let activeRemaining = 0;
          Object.values(batchProgress).forEach(b => {
              activeRemaining += (b.total - b.completed);
          });

          const pendingInQueue = extractionQueue.length;
          const calculatedCompleted = progress.total - pendingInQueue - activeRemaining;

          setProgress(prev => ({
              ...prev,
              completed: Math.max(0, calculatedCompleted)
          }));
      }

  }, [batchProgress, extractionQueue.length]);

  // --- Gemini Processing Logic ---
  useEffect(() => {
    Object.entries(results).forEach(([symbol, items]) => {
      items.forEach(async (item) => {
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        if (item.geminiParsingReq && 
            item.success && 
            typeof item.data === 'string' && 
            item.data.trim().startsWith('<') &&
            !processingRef.current.has(uniqueKey)
        ) {
            processingRef.current.add(uniqueKey);

            try {
                let dataToParse = item.data;
                if(item.indicatorName === "Insider/SAST Deals") {
                  dataToParse = getTopElementInnerHTML(item.data);
                }

                const jsonStr = await processRawInsightData(dataToParse, item.geminiPrompt, item.indicatorName);

                let jsonObj;
                try {
                    jsonObj = JSON.parse(jsonStr);
                    // MERGE NSE DATA FOR PE CARD
                    if (item.indicatorName === 'PE') {
                         try {
                             const secInfo = await fetchStockSecInfo(symbol);
                             if (secInfo) {
                                 jsonObj.secInfo = secInfo;
                             }
                         } catch(e) {
                             console.warn(`Failed to fetch NSE SecInfo for ${symbol}`, e);
                         }
                    }
                } catch(e) {
                    jsonObj = { error: "Failed to parse data output", raw: jsonStr };
                }

                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: jsonObj,
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            } catch (err) {
                console.error("Processing failed for", uniqueKey);
                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: { error: "Processing failed" },
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            }
        }
      });
    });
  }, [results]);

  return {
    results,
    setResults,
    status,
    setStatus,
    progress,
    setProgress,
    activeRequestIds,
    startExtraction
  };
};

import { FundSnapshot, StockHolding, StockMFAnalysis, MutualFundHolding, MFHoldingHistory, StockPriceData, FundPortfolioHolding, FundSearchResult, FundPortfolioData, FundMeta, SectorDistribution, HoldingHistoryItem } from '../types';
import { StockDataRequestItem, BulkExtractResponse, PollStatusResponse } from '../types/trackingTypes';
import { generateInsightConfig } from './trackingStorage';
import { extractStockDataFromHtml } from './geminiService';
import * as XLSX from 'xlsx';

const PROXY_BASE_URL = "https://stockmarketdata.linkpc.net/api/extract-data";
const BULK_API_URL = "https://stockmarketdata.linkpc.net/api/extractinsight";

export interface ProxyOptions {
  attribute?: string;
  attributeValue?: string;
  tagName?: string;
}

/**
 * Helper function to fetch data via the proxy service.
 * Constructs the URL with query parameters automatically.
 * Handles both JSON and raw text responses.
 */
export const fetchFromProxy = async (targetUrl: string, options: ProxyOptions = {}) => {
  const url = new URL(PROXY_BASE_URL);
  url.searchParams.append('url', targetUrl);

  if (options.attribute) url.searchParams.append('attribute', options.attribute);
  if (options.attributeValue) url.searchParams.append('attributeValue', options.attributeValue);
  if (options.tagName) url.searchParams.append('tagName', options.tagName);

  const response = await fetch(url.toString());
  if (!response.ok) {
      throw new Error(`Proxy request failed with status ${response.status}: ${response.statusText}`);
  }

  const contentType = response.headers.get("content-type");
  let data;
  if (contentType && contentType.includes("application/json")) {
    data = await response.json();
  } else {
    // Fallback for raw string/html responses
    data = await response.text();
  }

  // Handle multi-attribute response or single attribute unwrapping
  if (options.attribute && typeof data === 'object' && data !== null && !Array.isArray(data)) {
      // If asking for multiple attributes (comma-separated), return the whole object
      if (options.attribute.includes(',')) {
          return data;
      }

      // Backward compatibility: If single attribute request returns keyed object, unwrap it
      if (Object.prototype.hasOwnProperty.call(data, options.attribute)) {
          return data[options.attribute];
      }
  }

  return data;
};

