import React from 'react';
import { TrendingUp, Briefcase, Activity, Layers, ExternalLink, Gauge, RefreshCw, Square, CheckSquare } from 'lucide-react';
import { ProcessedInsight } from '../../../services/indicatorProcessor';

interface IntelligentStockCardProps {
  symbol: string;
  insights: ProcessedInsight[];
  isTracked: boolean;
  onOpenDeepDive: () => void;
  onAskAI: () => void;
  onRefresh: () => void;
  isSelected: boolean;
  onToggleSelect: () => void;
}

const IntelligentStockCard: React.FC<IntelligentStockCardProps> = ({ 
  symbol, 
  insights,
  isTracked,
  onOpenDeepDive,
  onAskAI,
  onRefresh,
  isSelected,
  onToggleSelect
}) => {

  const groupInsights = () => {
      const groups = {
          Valuation: [] as ProcessedInsight[],
          Technicals: [] as ProcessedInsight[],
          Holdings: [] as ProcessedInsight[],
          Performance: [] as ProcessedInsight[],
          Deals: [] as ProcessedInsight[]
      };

      insights.forEach(i => {
          if (i.type && groups[i.type]) {
              groups[i.type].push(i);
          }
      });
      return groups;
  };

  const grouped = groupInsights();
  const hasData = insights.length > 0;

  const renderSection = (title: string, items: ProcessedInsight[], icon: React.ReactNode, bgClass: string, textClass: string) => {
      if (items.length === 0) return null;

      return (
          <div className="mb-3 last:mb-0">
             <div className="flex items-center gap-1.5 mb-1.5">
                <div className={`p-1 rounded ${bgClass} ${textClass}`}>
                    {icon}
                </div>
                <span className={`text-[10px] font-bold uppercase tracking-wider ${textClass}`}>{title}</span>
             </div>
             <div className="space-y-1.5">
                 {items.map((item, idx) => (
                     <div key={idx} className="text-xs text-gray-700 bg-gray-50 p-2 rounded border border-gray-100 leading-snug">
                         {item.text}
                     </div>
                 ))}
             </div>
          </div>
      );
  };

  return (
    <div className={`bg-white rounded-xl border shadow-sm hover:shadow-md transition-all flex flex-col h-full group ${isSelected ? 'border-indigo-500 ring-1 ring-indigo-500' : 'border-gray-200'}`}>
        {/* Header */}
        <div className="p-3 border-b border-gray-100 flex items-center justify-between bg-gray-50/50 rounded-t-xl">
             {/* Left: Selection & Symbol */}
             <div className="flex items-center gap-2 flex-1 min-w-0">
                 <button 
                    onClick={(e) => { e.stopPropagation(); onToggleSelect(); }}
                    className={`shrink-0 text-gray-400 hover:text-indigo-600 transition-colors`}
                    title="Select Card"
                 >
                    {isSelected ? <CheckSquare size={18} className="text-indigo-600" /> : <Square size={18} />}
                 </button>

                 <div 
                    onClick={onOpenDeepDive}
                    className="flex items-center gap-2 text-left cursor-pointer hover:bg-gray-100 p-1 rounded-lg transition-colors flex-1 min-w-0"
                    title="Click for Deep Dive Analysis"
                 >
                     <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 ${isTracked ? 'bg-green-100 text-green-700' : 'bg-indigo-100 text-indigo-700'}`}>
                        {symbol[0]}
                     </div>
                     <div className="min-w-0">
                        <h3 className="font-bold text-gray-900 text-sm leading-tight truncate">
                            {symbol}
                        </h3>
                        <div className="text-[10px] text-gray-500 font-medium truncate">
                            {insights.length} Insight{insights.length !== 1 ? 's' : ''} Found
                        </div>
                     </div>
                 </div>
             </div>

             {/* Right: Actions */}
             <div className="flex items-center gap-1">
                 {/* External Link */}
                 <a 
                    href={`https://trendlyne.com/equity/${symbol}/stock-page/`}
                    target="_blank"
                    rel="noreferrer"
                    className="p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-white rounded-md transition-all"
                    title="View on Trendlyne"
                    onClick={(e) => e.stopPropagation()}
                 >
                    <ExternalLink size={14} />
                 </a>

                 {/* Single Card Refresh */}
                 <button 
                    onClick={(e) => { e.stopPropagation(); onRefresh(); }}
                    className="p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-white rounded-md transition-all"
                    title="Force Refresh Data"
                 >
                    <RefreshCw size={14} />
                 </button>
             </div>
        </div>

        {/* Body */}
        <div className="p-3 flex-1 overflow-y-auto max-h-[300px] custom-scrollbar">
            {hasData ? (
                <>
                   {renderSection("Valuation", grouped.Valuation, <Activity size={12}/>, "bg-blue-50", "text-blue-700")}
                   {renderSection("Technicals", grouped.Technicals, <Gauge size={12}/>, "bg-cyan-50", "text-cyan-700")}
                   {renderSection("Institutional Holdings", grouped.Holdings, <Briefcase size={12}/>, "bg-purple-50", "text-purple-700")}
                   {renderSection("Performance Trend", grouped.Performance, <TrendingUp size={12}/>, "bg-green-50", "text-green-700")}
                   {renderSection("Deals & Insider", grouped.Deals, <Layers size={12}/>, "bg-orange-50", "text-orange-700")}
                </>
            ) : (
                <div className="h-full flex items-center justify-center text-gray-400 text-xs italic">
                    No significant triggers found.
                </div>
            )}
        </div>

        {/* Footer */}
        <div className="p-3 border-t border-gray-100 mt-auto flex gap-2">
             <button 
                onClick={onAskAI}
                className="flex-1 py-1.5 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 rounded text-xs font-medium transition-colors flex items-center justify-center gap-1.5"
             >
                <Briefcase size={12} /> Ask AI
             </button>
        </div>
    </div>
  );
};

export default IntelligentStockCard;

import React, { useState, useEffect } from 'react';
import { Settings, Info } from 'lucide-react';
import EntityList from './EntityList';
import IndexWatchlist from './IndexWatchlist';
import IgnoreList from './IgnoreList';
import { getTrackedItems, removeTrackedItem, TrackedItem, getIgnoredItems, removeIgnoredItem } from '../../services/trackingStorage';
import { FundSearchResult } from '../../types';

interface ConfigurationViewProps {
  onSelectStock: (symbol: string, name: string) => void;
  onSelectFund: (fund: FundSearchResult) => void;
}

const ConfigurationView: React.FC<ConfigurationViewProps> = ({ onSelectStock, onSelectFund }) => {
  const [items, setItems] = useState<TrackedItem[]>([]);
  const [ignoredItems, setIgnoredItems] = useState<string[]>([]);

  useEffect(() => {
    refreshItems();
  }, []);

  const refreshItems = () => {
    setItems(getTrackedItems());
    setIgnoredItems(getIgnoredItems());
  };

  const handleRemove = (id: string, type: 'STOCK' | 'MF') => {
    removeTrackedItem(id, type);
    refreshItems();
  };

  const handleRemoveIgnored = (symbol: string) => {
      removeIgnoredItem(symbol);
      refreshItems();
  }

  const handleItemClick = (item: TrackedItem) => {
    if (item.type === 'STOCK') {
      onSelectStock(item.id, item.name);
    } else {
      // Reconstruct FundSearchResult
      onSelectFund({
        name: item.name,
        url: item.url || '',
        pk: !isNaN(Number(item.id)) ? Number(item.id) : undefined
      });
    }
  };

  const handleIgnoreClick = (symbol: string) => {
      onSelectStock(symbol, symbol);
  };

  const stockItems = items.filter(i => i.type === 'STOCK');
  const mfItems = items.filter(i => i.type === 'MF');

  return (
    <div className="max-w-7xl mx-auto space-y-6 animate-fade-in flex flex-col h-[calc(100vh-100px)] min-h-[800px]">
      <div className="flex items-center gap-3 pb-4 border-b border-gray-100 shrink-0">
        <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg">
          <Settings size={24} />
        </div>
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Configure Watchlist</h1>
          <p className="text-gray-500 text-sm">Manage the entities, indices, and ignored items in your dashboard.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 flex-1 min-h-0">

        {/* Column 1: Stocks (Top) & Ignored (Bottom) - 50/50 Split */}
        <div className="flex flex-col gap-6 h-full min-h-0">
            <div className="flex-1 min-h-0">
                <EntityList 
                  title="Tracked Stocks" 
                  items={stockItems} 
                  type="STOCK" 
                  onRemove={(id) => handleRemove(id, 'STOCK')}
                  onItemClick={handleItemClick}
                />
            </div>
            <div className="flex-1 min-h-0">
                <IgnoreList 
                    items={ignoredItems}
                    onRemove={handleRemoveIgnored}
                    onItemClick={handleIgnoreClick}
                />
            </div>
        </div>

        {/* Column 2: Mutual Funds */}
        <div className="h-full min-h-0">
            <EntityList 
              title="Tracked Mutual Funds" 
              items={mfItems} 
              type="MF" 
              onRemove={(id) => handleRemove(id, 'MF')} 
              onItemClick={handleItemClick}
            />
        </div>

        {/* Column 3: Indices */}
        <div className="h-full min-h-0">
            <IndexWatchlist />
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 rounded-xl p-4 flex items-start gap-3 text-blue-800 text-sm shrink-0">
         <Info size={18} className="mt-0.5 shrink-0" />
         <p>
           To add more items to your watchlist, visit the <strong>Stock Search</strong> or <strong>MF Search</strong> pages 
           and click the <span className="inline-flex items-center justify-center w-5 h-5 bg-indigo-600 text-white rounded text-xs font-bold leading-none mx-1">+</span> icon next to any result.
         </p>
      </div>
    </div>
  );
};

export default ConfigurationView;

